import React from 'react';
import ContactSection from './sections/ContactSection';
import SummarySection from './sections/SummarySection';
import ExperienceSection from './sections/ExperienceSection';
import EducationSection from './sections/EducationSection';
import SkillsSection from './sections/SkillsSection';
import PreviewSection from './sections/PreviewSection';
import SectionNavigation from './SectionNavigation';

function MainContent({ currentStep, resumeData, onUpdateData, onStepChange }) {
  const steps = ['contact', 'summary', 'experience', 'education', 'skills', 'preview'];

  const renderSection = () => {
    switch (currentStep) {
      case 0:
        return (
          <ContactSection 
            data={resumeData.contact}
            onUpdate={(data) => onUpdateData('contact', data)}
          />
        );
      case 1:
        return (
          <SummarySection 
            data={resumeData.summary}
            onUpdate={(data) => onUpdateData('summary', data)}
          />
        );
      case 2:
        return (
          <ExperienceSection 
            data={resumeData.experience}
            onUpdate={(data) => onUpdateData('experience', data)}
          />
        );
      case 3:
        return (
          <EducationSection 
            data={resumeData.education}
            onUpdate={(data) => onUpdateData('education', data)}
          />
        );
      case 4:
        return (
          <SkillsSection 
            data={resumeData.skills}
            onUpdate={(data) => onUpdateData('skills', data)}
          />
        );
      case 5:
        return (
          <PreviewSection 
            resumeData={resumeData}
          />
        );
      default:
        return null;
    }
  };

  return (
    <main className="main-content">
      {renderSection()}
      <SectionNavigation 
        currentStep={currentStep}
        totalSteps={steps.length}
        onPrevious={() => onStepChange(currentStep - 1)}
        onNext={() => onStepChange(currentStep + 1)}
      />
    </main>
  );
}

export default MainContent;
